40	ivec3 get_marching_cubes_res(uint32_t res_1d, const BoundingBox &aabb) {
41		float scale = res_1d / max(aabb.max - aabb.min);
42		ivec3 res3d = (aabb.max - aabb.min) * scale + 0.5f;
43		res3d.x = next_multiple((unsigned int)res3d.x, 16u);
44		res3d.y = next_multiple((unsigned int)res3d.y, 16u);
45		res3d.z = next_multiple((unsigned int)res3d.z, 16u);
46		return res3d;
47	}
