50	void glCheckError(const char* file, unsigned int line) {
51		GLenum errorCode = glGetError();
52		while (errorCode != GL_NO_ERROR) {
53			std::string fileString(file);
54			std::string error = "unknown error";
55			// clang-format off
56			switch (errorCode) {
57				case GL_INVALID_ENUM:      error = "GL_INVALID_ENUM"; break;
58				case GL_INVALID_VALUE:     error = "GL_INVALID_VALUE"; break;
59				case GL_INVALID_OPERATION: error = "GL_INVALID_OPERATION"; break;
60				case GL_STACK_OVERFLOW:    error = "GL_STACK_OVERFLOW"; break;
61				case GL_STACK_UNDERFLOW:   error = "GL_STACK_UNDERFLOW"; break;
62				case GL_OUT_OF_MEMORY:     error = "GL_OUT_OF_MEMORY"; break;
63			}
64			// clang-format on
65	
66			tlog::error() << "OpenglError : file=" << file << " line=" << line << " error:" << error;
67			errorCode = glGetError();
68		}
69	}
