71	bool check_shader(uint32_t handle, const char* desc, bool program) {
72		GLint status = 0, log_length = 0;
73		if (program) {
74			glGetProgramiv(handle, GL_LINK_STATUS, &status);
75			glGetProgramiv(handle, GL_INFO_LOG_LENGTH, &log_length);
76		} else {
77			glGetShaderiv(handle, GL_COMPILE_STATUS, &status);
78			glGetShaderiv(handle, GL_INFO_LOG_LENGTH, &log_length);
79		}
80		if ((GLboolean)status == GL_FALSE) {
81			tlog::error() << "Failed to compile shader: " << desc;
82		}
83		if (log_length > 1) {
84			std::vector<char> log; log.resize(log_length+1);
85			if (program) {
86				glGetProgramInfoLog(handle, log_length, NULL, (GLchar*)log.data());
87			} else {
88				glGetShaderInfoLog(handle, log_length, NULL, (GLchar*)log.data());
89			}
90			log.back() = 0;
91			tlog::error() << log.data();
92		}
93		return (GLboolean)status == GL_TRUE;
94	}
