96	uint32_t compile_shader(bool pixel, const char* code) {
97		GLuint g_VertHandle = glCreateShader(pixel ? GL_FRAGMENT_SHADER : GL_VERTEX_SHADER );
98		const char* glsl_version = "#version 140\n";
99		const GLchar* strings[2] = { glsl_version, code};
100		glShaderSource(g_VertHandle, 2, strings, NULL);
101		glCompileShader(g_VertHandle);
102		if (!check_shader(g_VertHandle, pixel? "pixel" : "vertex", false)) {
103			glDeleteShader(g_VertHandle);
104			return 0;
105		}
106		return g_VertHandle;
107	}
