109	void draw_mesh_gl(
110		const GPUMemory<vec3>& verts,
111		const GPUMemory<vec3>& normals,
112		const GPUMemory<vec3>& colors,
113		const GPUMemory<uint32_t>& indices,
114		const ivec2& resolution,
115		const vec2& focal_length,
116		const mat4x3& camera_matrix,
117		const vec2& screen_center,
118		int mesh_render_mode
119	) {
120		if (verts.size() == 0 || indices.size() == 0 || mesh_render_mode == 0) {
121			return;
122		}
123	
124		static GLuint vs = 0, ps = 0, program = 0, VAO = 0, VBO[3] = {}, els = 0, vbosize = 0, elssize = 0;
125		if (!VAO) {
126			glGenVertexArrays(1, &VAO);
127			glBindVertexArray(VAO);
128		}
129		if (vbosize != verts.size()) {
130			for (int i= 0; i < 3; ++i) {
131				if (VBO[i]) {
132					cudaGLUnregisterBufferObject(VBO[i]);
133					glDeleteBuffers(1, &VBO[i]);
134				}
135				glGenBuffers(1, &VBO[i]);
136				vbosize = verts.size();
137				glBindBuffer(GL_ARRAY_BUFFER, VBO[i]);
138				glBufferData(GL_ARRAY_BUFFER, vbosize * sizeof(vec3), NULL, GL_DYNAMIC_COPY);
139				cudaGLRegisterBufferObject(VBO[i]);
140			}
141		}
142		if (elssize != indices.size()) {
143			if (els) {
144				cudaGLUnregisterBufferObject(els);
145				glDeleteBuffers(1, &els);
146			}
147			glGenBuffers(1, &els);
148			elssize = indices.size();
149			glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, els);
150			glBufferData(GL_ELEMENT_ARRAY_BUFFER, elssize * sizeof(int), NULL, GL_STREAM_DRAW);
151			cudaGLRegisterBufferObject(els);
152		}
153		void *ptr=nullptr;
154		cudaGLMapBufferObject(&ptr, VBO[0]);
155		if (ptr) cudaMemcpy(ptr, verts.data(), vbosize * sizeof(vec3), cudaMemcpyDeviceToDevice);
156		cudaGLMapBufferObject(&ptr, VBO[1]);
157		if (ptr) cudaMemcpy(ptr, normals.data(), vbosize * sizeof(vec3), cudaMemcpyDeviceToDevice);
158		cudaGLMapBufferObject(&ptr, VBO[2]);
159		if (ptr) cudaMemcpy(ptr, colors.data(), vbosize * sizeof(vec3), cudaMemcpyDeviceToDevice);
160	
161		//std::vector<vec3> cpucols; cpucols.resize(verts.size());
162		//colors.copy_to_host(cpucols);
163	
164		cudaGLUnmapBufferObject(VBO[2]);
165		cudaGLUnmapBufferObject(VBO[1]);
166		cudaGLUnmapBufferObject(VBO[0]);
167		cudaGLMapBufferObject(&ptr, els);
168		if (ptr) cudaMemcpy(ptr, indices.data(), indices.get_bytes(), cudaMemcpyDeviceToDevice);
169		cudaGLUnmapBufferObject(els);
170	
171		if (!program) {
172			vs = compile_shader(false, R"foo(
173	in vec3 pos;
174	in vec3 nor;
175	in vec3 col;
176	out vec3 vtxcol;
177	uniform mat4 camera;
178	uniform vec2 f;
179	uniform ivec2 res;
180	uniform vec2 cen;
181	uniform int mode;
182	void main()
183	{
184		vec4 p = camera * vec4(pos, 1.0);
185		p.xy *= vec2(2.0, -2.0) * f.xy / vec2(res.xy);
186		p.w = p.z;
187		p.z = p.z - 0.1;
188		p.xy += cen * p.w;
189		if (mode == 2) {
190			vtxcol = normalize(nor) * 0.5 + vec3(0.5); // visualize vertex normals
191		} else {
192			vtxcol = col;
193		}
194		gl_Position = p;
195	}
196	)foo");
197			ps = compile_shader(true, R"foo(
198	out vec4 o;
199	in vec3 vtxcol;
200	uniform int mode;
201	void main() {
202		o = vec4(vtxcol, 1.0);
203	}
204	)foo");
205			program = glCreateProgram();
206			glAttachShader(program, vs);
207			glAttachShader(program, ps);
208			glLinkProgram(program);
209			if (!check_shader(program, "shader program", true)) {
210				glDeleteProgram(program);
211				program = 0;
212			}
213		}
214		mat4 view2world = camera_matrix;
215		mat4 world2view = inverse(view2world);
216		glBindVertexArray(VAO);
217		glUseProgram(program);
218		glUniformMatrix4fv(glGetUniformLocation(program, "camera"), 1, GL_FALSE, (GLfloat*)&world2view);
219		glUniform2f(glGetUniformLocation(program, "f"), focal_length.x, focal_length.y);
220		glUniform2f(glGetUniformLocation(program, "cen"), screen_center.x*2.f-1.f, screen_center.y*-2.f+1.f);
221		glUniform2i(glGetUniformLocation(program, "res"), resolution.x, resolution.y);
222		glUniform1i(glGetUniformLocation(program, "mode"), mesh_render_mode);
223		glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, els);
224		GLuint posat = (GLuint)glGetAttribLocation(program, "pos");
225		GLuint norat = (GLuint)glGetAttribLocation(program, "nor");
226		GLuint colat = (GLuint)glGetAttribLocation(program, "col");
227		glEnableVertexAttribArray(posat);
228		glEnableVertexAttribArray(norat);
229		glEnableVertexAttribArray(colat);
230		glBindBuffer(GL_ARRAY_BUFFER, VBO[0]);
231		glVertexAttribPointer(posat, 3, GL_FLOAT, GL_FALSE, 3*4, 0);
232		glBindBuffer(GL_ARRAY_BUFFER, VBO[1]);
233		glVertexAttribPointer(norat, 3, GL_FLOAT, GL_FALSE, 3*4, 0);
234		glBindBuffer(GL_ARRAY_BUFFER, VBO[2]);
235		glVertexAttribPointer(colat, 3, GL_FLOAT, GL_FALSE, 3*4, 0);
236		glCullFace(GL_BACK);
237		glDisable(GL_CULL_FACE);
238		glEnable(GL_DEPTH_TEST);
239		glDrawElements(GL_TRIANGLES, (GLsizei)indices.size(), GL_UNSIGNED_INT , (GLvoid*)0);
240		glDisable(GL_CULL_FACE);
241	
242		glUseProgram(0);
243	}
244	#endif //NGP_GUI
