246	/*
247	vertex indices with z=0
248	0 -> 1   <-- first edge is 0->1, then 1->2 etc
249	^    |
250	|	 v
251	3 <- 2
252	
253	with z=1
254	4 -> 5   <-- fourth edge is 4->5 etc
255	^    |
256	|	 v
257	7 <- 6
258	
259	edges 8-11 go in +z direction from vertex 0-3
260	*/
261	__global__ void gen_vertices(BoundingBox render_aabb, mat3 render_aabb_to_local, ivec3 res_3d, const float* __restrict__ density, int*__restrict__ vertidx_grid, vec3* verts_out, float thresh, uint32_t* __restrict__ counters) {
262		uint32_t x = blockIdx.x * blockDim.x + threadIdx.x;
263		uint32_t y = blockIdx.y * blockDim.y + threadIdx.y;
264		uint32_t z = blockIdx.z * blockDim.z + threadIdx.z;
265		if (x>=res_3d.x || y>=res_3d.y || z>=res_3d.z) return;
266		vec3 scale = (render_aabb.max - render_aabb.min) / vec3(res_3d - 1);
267		vec3 offset=render_aabb.min;
268		uint32_t res2=res_3d.x*res_3d.y;
269		uint32_t res3=res_3d.x*res_3d.y*res_3d.z;
270		uint32_t idx=x+y*res_3d.x+z*res2;
271		float f0 = density[idx];
272		bool inside=(f0>thresh);
273		if (x<res_3d.x-1) {
274			float f1 = density[idx+1];
275			if (inside != (f1>thresh)) {
276				uint32_t vidx = atomicAdd(counters,1);
277				if (verts_out) {
278					vertidx_grid[idx]=vidx+1;
279					float prevf=f0,nextf=f1;
280					float dt=((thresh-prevf)/(nextf-prevf));
281					verts_out[vidx] = transpose(render_aabb_to_local) * (vec3{float(x)+dt, float(y), float(z)} * scale + offset);
282				}
283			}
284		}
285		if (y<res_3d.y-1) {
286			float f1 = density[idx+res_3d.x];
287			if (inside != (f1>thresh)) {
288				uint32_t vidx = atomicAdd(counters,1);
289				if (verts_out) {
290					vertidx_grid[idx+res3]=vidx+1;
291					float prevf=f0,nextf=f1;
292					float dt=((thresh-prevf)/(nextf-prevf));
293					verts_out[vidx] = transpose(render_aabb_to_local) * (vec3{float(x), float(y)+dt, float(z)} * scale + offset);
294				}
295			}
296		}
297		if (z<res_3d.z-1) {
298			float f1 = density[idx+res2];
299			if (inside != (f1>thresh)) {
300				uint32_t vidx = atomicAdd(counters,1);
301				if (verts_out) {
302					vertidx_grid[idx+res3*2]=vidx+1;
303					float prevf=f0,nextf=f1;
304					float dt=((thresh-prevf)/(nextf-prevf));
305					verts_out[vidx] = transpose(render_aabb_to_local) * (vec3{float(x), float(y), float(z)+dt} * scale + offset);
306				}
307			}
308		}
309	}
310	
311	__global__ void accumulate_1ring(uint32_t num_tris, const uint32_t* indices, const vec3* verts_in, vec4* verts_out, vec3 *normals_out) {
312		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
313		if (i>=num_tris) return;
314		uint32_t ia=indices[i*3+0];
315		uint32_t ib=indices[i*3+1];
316		uint32_t ic=indices[i*3+2];
317		vec3 pa=verts_in[ia];
318		vec3 pb=verts_in[ib];
319		vec3 pc=verts_in[ic];
320	
321		atomicAdd(&verts_out[ia][0], pb.x+pc.x);
322		atomicAdd(&verts_out[ia][1], pb.y+pc.y);
323		atomicAdd(&verts_out[ia][2], pb.z+pc.z);
324		atomicAdd(&verts_out[ia][3], 2.f);
325		atomicAdd(&verts_out[ib][0], pa.x+pc.x);
326		atomicAdd(&verts_out[ib][1], pa.y+pc.y);
327		atomicAdd(&verts_out[ib][2], pa.z+pc.z);
328		atomicAdd(&verts_out[ib][3], 2.f);
329		atomicAdd(&verts_out[ic][0], pb.x+pa.x);
330		atomicAdd(&verts_out[ic][1], pb.y+pa.y);
331		atomicAdd(&verts_out[ic][2], pb.z+pa.z);
332		atomicAdd(&verts_out[ic][3], 2.f);
333	
334		if (normals_out) {
335			vec3 n= cross(pb - pa, pa - pc); // don't normalise so it's weighted by area
336			atomicAdd(&normals_out[ia][0], n.x);
337			atomicAdd(&normals_out[ia][1], n.y);
338			atomicAdd(&normals_out[ia][2], n.z);
339			atomicAdd(&normals_out[ib][0], n.x);
340			atomicAdd(&normals_out[ib][1], n.y);
341			atomicAdd(&normals_out[ib][2], n.z);
342			atomicAdd(&normals_out[ic][0], n.x);
343			atomicAdd(&normals_out[ic][1], n.y);
344			atomicAdd(&normals_out[ic][2], n.z);
345		}
346	}
347	
348	__global__ void compute_centroids(uint32_t num_verts, vec3* centroids_out, const vec4* verts_in) {
349		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
350		if (i>=num_verts) return;
351		vec4 p = verts_in[i];
352		if (p.w<=0.f) return;
353		vec3 c = verts_in[i].xyz() * (1.f / p.w);
354		centroids_out[i]=c;
355	}
