641		uint32_t x = blockIdx.x * blockDim.x + threadIdx.x;
642		uint32_t y = blockIdx.y * blockDim.y + threadIdx.y;
643		uint32_t z = blockIdx.z * blockDim.z + threadIdx.z;
644		if (x>=res_3d.x-1 || y>=res_3d.y-1 || z>=res_3d.z-1) return;
645		uint32_t res1=res_3d.x;
646		uint32_t res2=res_3d.x*res_3d.y;
647		uint32_t res3=res_3d.x*res_3d.y*res_3d.z;
648		uint32_t idx=x+y*res_3d.x+z*res2;
649	
650		uint32_t idx_x=idx;
651		uint32_t idx_y=idx+res3;
652		uint32_t idx_z=idx+res3*2;
653	
654		int mask=0;
655		if (density[idx]>thresh) mask|=1;
656		if (density[idx+1]>thresh) mask|=2;
657		if (density[idx+1+res1]>thresh) mask|=4;
658		if (density[idx+res1]>thresh) mask|=8;
659		idx+=res2;
660		if (density[idx]>thresh) mask|=16;
661		if (density[idx+1]>thresh) mask|=32;
662		if (density[idx+1+res1]>thresh) mask|=64;
663		if (density[idx+res1]>thresh) mask|=128;
664		idx-=res2;
665	
666		if (!mask || mask==255) return;
667		int local_edges[12];
668		if (vertidx_grid) {
669			local_edges[0]=vertidx_grid[idx_x];
670			local_edges[1]=vertidx_grid[idx_y+1];
671			local_edges[2]=vertidx_grid[idx_x+res1];
672			local_edges[3]=vertidx_grid[idx_y];
673	
674			local_edges[4]=vertidx_grid[idx_x+res2];
675			local_edges[5]=vertidx_grid[idx_y+1+res2];
676			local_edges[6]=vertidx_grid[idx_x+res1+res2];
677			local_edges[7]=vertidx_grid[idx_y+res2];
678	
679			local_edges[8]=vertidx_grid[idx_z];
680			local_edges[9]=vertidx_grid[idx_z+1];
681			local_edges[10]=vertidx_grid[idx_z+1+res1];
682			local_edges[11]=vertidx_grid[idx_z+res1];
683		}
684		uint32_t tricount=0;
685		const int8_t *triangles=triangle_table[mask];
686		for (;tricount<15;tricount+=3) if (triangles[tricount]<0) break;
687		uint32_t tidx = atomicAdd(counters+1,tricount);
688		if (indices_out) {
689			for (int i=0;i<15;++i) {
690				int j = triangles[i];
691				if (j<0) break;
692				if (!local_edges[j]) {
693					printf("at %d %d %d, mask is %d, j is %d, local_edges is 0\n", x,y,z,mask,j);
694				}
695				indices_out[tidx+i]=local_edges[j]-1;
696			}
697		}
