708	__global__ void compute_mesh_opt_gradients_kernel(
709		uint32_t n_verts,
710		float thresh,
711		const vec3* verts,
712		const vec3* normals,
713		const vec4* verts_smoothed,
714		const network_precision_t* densities,
715		uint32_t input_gradient_width,
716		const float* input_gradients,
717		vec3* verts_gradient_out,
718		float k_smooth_amount,
719		float k_density_amount,
720		float k_inflate_amount
721	) {
722		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
723		if (i >= n_verts) return;
724	
725		vec3 src = verts[i];
726		vec4 p = verts_smoothed[i];
727	
728		if (p.w <= 0.f) {
729			p.w = 1.f;
730		}
731	
732		vec3 target = p.xyz() * (1.0f / p.w);
733		vec3 smoothing_grad = src - target; // negative...
734	
735		vec3 input_gradient = *(const vec3 *)(input_gradients + i * input_gradient_width);
736	
737		vec3 n = normalize(input_gradient);
738		float density = densities[i];
739		verts_gradient_out[i] = n * sign(density - thresh) * k_density_amount + smoothing_grad * k_smooth_amount - normalize(normals[i]) * k_inflate_amount;
740	}
741	
742	void compute_mesh_opt_gradients(
743		float thresh,
744		const GPUMemory<vec3>& verts,
745		const GPUMemory<vec3>& normals,
746		const GPUMemory<vec4>& verts_smoothed,
747		const network_precision_t* densities,
748		uint32_t input_gradients_width,
749		const float* input_gradients,
750		GPUMemory<vec3>& verts_gradient_out,
751		float k_smooth_amount,
752		float k_density_amount,
753		float k_inflate_amount
754	) {
755		linear_kernel(
756			compute_mesh_opt_gradients_kernel,
757			0,
758			nullptr,
759			verts.size(),
760			thresh,
761			verts.data(),
762			normals.data(),
763			verts_smoothed.data(),
764			densities,
765			input_gradients_width,
766			input_gradients,
767			verts_gradient_out.data(),
768			k_smooth_amount,
769			k_density_amount,
770			k_inflate_amount
771		);
772	}
