805	void save_mesh(
806		GPUMemory<vec3>& verts,
807		GPUMemory<vec3>& normals,
808		GPUMemory<vec3>& colors,
809		GPUMemory<uint32_t>& indices,
810		const fs::path& path,
811		bool unwrap_it,
812		float nerf_scale,
813		vec3 nerf_offset
814	) {
815		std::vector<vec3> cpuverts; cpuverts.resize(verts.size());
816		std::vector<vec3> cpunormals; cpunormals.resize(normals.size());
817		std::vector<vec3> cpucolors; cpucolors.resize(colors.size());
818		std::vector<uint32_t> cpuindices; cpuindices.resize(indices.size());
819		verts.copy_to_host(cpuverts);
820		normals.copy_to_host(cpunormals);
821		colors.copy_to_host(cpucolors);
822		indices.copy_to_host(cpuindices);
823	
824		// Replace invalid values with reasonable defaults
825		for (size_t i = 0; i < cpuverts.size(); ++i) {
826			if (!all(isfinite(cpuverts[i]))) cpuverts[i] = vec3(0.0f);
827			if (!all(isfinite(cpunormals[i]))) cpunormals[i] = vec3{0.0f, 1.0f, 0.0f};
828			if (!all(isfinite(cpucolors[i]))) cpucolors[i] = vec3(0.0f);
829		}
830	
831		uint32_t numquads = ((cpuindices.size()/3)+1)/2;
832		uint32_t numquadsx = uint32_t(sqrtf(numquads)+4) & (~3);
833		uint32_t numquadsy = (numquads+numquadsx-1)/numquadsx;
834		uint32_t quadresy = 8;
835		uint32_t quadresx = quadresy+3;
836		uint32_t texw = quadresx*numquadsx;
837		uint32_t texh = quadresy*numquadsy;
838	
839		if (unwrap_it) {
840			uint8_t* tex = (uint8_t*)malloc(texw*texh*3);
841			for (uint32_t y = 0; y < texh; ++y) {
842				for (uint32_t x = 0; x < texw; ++x) {
843					uint32_t q = (x/quadresx)+(y/quadresy)*numquadsx;
844					// 0 x x 3 - - 4
845					// | .\x x\. . |
846					// | . .\x x\. |
847					// 2 - - 1 x x 5
848					uint32_t xi = x % quadresx, yi = y % quadresy;
849					uint32_t t = q*2 + (xi>yi+1);
850					int r = (t*923)&255;
851					int g = (t*3572)&255;
852					int b = (t*5423)&255;
853					//if (xi==yi+1 || xi==yi+2)
854					//	r=g=b=0;
855					tex[x*3+y*3*texw+0]=r;
856					tex[x*3+y*3*texw+1]=g;
857					tex[x*3+y*3*texw+2]=b;
858				}
859			}
860	
861			write_stbi(path.with_extension(".tga"), texw, texh, 3, tex);
862			free(tex);
863		}
864	
865		FILE* f = native_fopen(path, "wb");
866		if (!f) {
867			throw std::runtime_error{fmt::format("Failed to open '{}' for writing", path.str())};
868		}
869	
870		if (equals_case_insensitive(path.extension(), "ply")) {
871			// ply file
872			fprintf(f,
873				"ply\n"
874				"format ascii 1.0\n"
875				"comment output from https://github.com/NVlabs/instant-ngp\n"
876				"element vertex %u\n"
877				"property float x\n"
878				"property float y\n"
879				"property float z\n"
880				"property float nx\n"
881				"property float ny\n"
882				"property float nz\n"
883				"property uchar red\n"
884				"property uchar green\n"
885				"property uchar blue\n"
886				"element face %u\n"
887				"property list uchar int vertex_index\n"
888				"end_header\n"
889				, (unsigned int)cpuverts.size()
890				, (unsigned int)cpuindices.size()/3
891			);
892	
893			for (size_t i=0;i<cpuverts.size();++i) {
894				vec3 p = (cpuverts[i]-nerf_offset)/nerf_scale;
895				vec3 c = cpucolors[i];
896				vec3 n = normalize(cpunormals[i]);
897				unsigned char c8[3] = {(unsigned char)clamp(c.x*255.f,0.f,255.f),(unsigned char)clamp(c.y*255.f,0.f,255.f),(unsigned char)clamp(c.z*255.f,0.f,255.f)};
898				fprintf(f, "%0.5f %0.5f %0.5f %0.3f %0.3f %0.3f %d %d %d\n", p.x, p.y, p.z, n.x, n.y, n.z, c8[0], c8[1], c8[2]);
899			}
900	
901			for (size_t i = 0; i < cpuindices.size(); i += 3) {
902				fprintf(f, "3 %d %d %d\n", cpuindices[i+2], cpuindices[i+1], cpuindices[i+0]);
903			}
904		} else {
905			// obj file
906			if (unwrap_it) {
907				fprintf(f, "mtllib nerf.mtl\n");
908			}
909	
910			for (size_t i = 0; i < cpuverts.size(); ++i) {
911				vec3 p = (cpuverts[i]-nerf_offset)/nerf_scale;
912				vec3 c = cpucolors[i];
913				fprintf(f, "v %0.5f %0.5f %0.5f %0.3f %0.3f %0.3f\n", p.x, p.y, p.z, clamp(c.x, 0.f, 1.f), clamp(c.y, 0.f, 1.f), clamp(c.z, 0.f, 1.f));
914			}
915	
916			for (auto &v: cpunormals) {
917				auto n = normalize(v);
918				fprintf(f, "vn %0.5f %0.5f %0.5f\n", n.x, n.y, n.z);
919			}
920	
921			if (unwrap_it) {
922				for (size_t i = 0; i < cpuindices.size(); i++) {
923					uint32_t q = (uint32_t)(i/6);
924					uint32_t x = (q%numquadsx)*quadresx;
925					uint32_t y = (q/numquadsx)*quadresy;
926					uint32_t d = quadresy-1;
927					switch (i % 6) {
928						case 0: break;
929						case 1: x += d; y += d; break;
930						case 2: y += d; break;
931						case 3: x += 3; break;
932						case 4: x += 3+d; break;
933						case 5: x += 3+d; y += d; break;
934					}
935					fprintf(f, "vt %0.5f %0.5f\n", ((float)x+0.5f)/float(texw), 1.f-((float)y+0.5f)/float(texh));
936				}
937	
938				fprintf(f, "g default\nusemtl nerf\ns 1\n");
939				for (size_t i = 0; i < cpuindices.size(); i += 3) {
940					fprintf(f,"f %u/%u/%u %u/%u/%u %u/%u/%u\n",
941						cpuindices[i+2]+1,(uint32_t)i+3,  cpuindices[i+2]+1,
942						cpuindices[i+1]+1,(uint32_t)i+2,cpuindices[i+1]+1,
943						cpuindices[i+0]+1,(uint32_t)i+1,cpuindices[i+0]+1
944					);
945				}
946			} else {
947				for (size_t i = 0; i < cpuindices.size(); i += 3) {
948					fprintf(f, "f %u//%u %u//%u %u//%u\n",
949						cpuindices[i+2]+1, cpuindices[i+2]+1, cpuindices[i+1]+1, cpuindices[i+1]+1, cpuindices[i+0]+1, cpuindices[i+0]+1
950					);
951				}
952			}
953		}
954		fclose(f);
955	}
956	
957	void save_density_grid_to_png(const GPUMemory<float>& density, const fs::path& path, ivec3 res3d, float thresh, bool swap_y_z, float density_range) {
958		float density_scale = 128.f / density_range; // map from -density_range to density_range into 0-255
959		std::vector<float> density_cpu;
960		density_cpu.resize(density.size());
961		density.copy_to_host(density_cpu);
962		uint32_t num_voxels = 0;
963		uint32_t num_lattice_points_near_zero_crossing = 0;
964		uint32_t N = res3d.x*res3d.y*res3d.z;
965		for (int z = 1; z < res3d.z - 1; ++z) {
966			for (int y = 1; y < res3d.y - 1; ++y) {
967				for (int x = 1; x < res3d.x - 1; ++x) {
968					int count = 0;
969					count += density_cpu[(x+0)+(y+0)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh;
970					count += density_cpu[(x+1)+(y+0)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh;
971					count += density_cpu[(x+0)+(y+1)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh;
972					count += density_cpu[(x+1)+(y+1)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh;
973					count += density_cpu[(x+0)+(y+0)*res3d.x+(z+1)*res3d.x*res3d.y] < thresh;
974					count += density_cpu[(x+1)+(y+0)*res3d.x+(z+1)*res3d.x*res3d.y] < thresh;
975					count += density_cpu[(x+0)+(y+1)*res3d.x+(z+1)*res3d.x*res3d.y] < thresh;
976					count += density_cpu[(x+1)+(y+1)*res3d.x+(z+1)*res3d.x*res3d.y] < thresh;
977					if (count>0 && count<8) {
978						num_voxels++;
979					}
980	
981					bool mysign = density_cpu[(x+0)+(y+0)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh;
982					bool near_zero_crossing=false;
983					near_zero_crossing |= (density_cpu[(x+1)+(y+0)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh) != mysign;
984					near_zero_crossing |= (density_cpu[(x-1)+(y+0)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh) != mysign;
985					near_zero_crossing |= (density_cpu[(x+0)+(y+1)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh) != mysign;
986					near_zero_crossing |= (density_cpu[(x+0)+(y-1)*res3d.x+(z+0)*res3d.x*res3d.y] < thresh) != mysign;
987					near_zero_crossing |= (density_cpu[(x+0)+(y+0)*res3d.x+(z+1)*res3d.x*res3d.y] < thresh) != mysign;
988					near_zero_crossing |= (density_cpu[(x+0)+(y+0)*res3d.x+(z-1)*res3d.x*res3d.y] < thresh) != mysign;
989					if (near_zero_crossing) {
990						num_lattice_points_near_zero_crossing++;
991					}
992				}
993			}
994		}
995	
996	
997		if (swap_y_z) {
998			res3d = {res3d.x, res3d.z, res3d.y};
999		}
1000	
1001		uint32_t ndown = uint32_t(sqrtf(res3d.z));
1002		uint32_t nacross = (res3d.z+ndown-1)/ndown;
1003		uint32_t w = res3d.x * nacross;
1004		uint32_t h = res3d.y * ndown;
1005		uint8_t* pngpixels = (uint8_t *)malloc(size_t(w)*size_t(h));
1006		uint8_t* dst = pngpixels;
1007		for (int v = 0; v < h; ++v) {
1008			for (int u = 0; u < w; ++u) {
1009				int x = u % res3d.x;
1010				int y = v % res3d.y;
1011				int z = (u / res3d.x) + (v / res3d.y) * nacross;
1012				if (z < res3d.z) {
1013					if (swap_y_z) {
1014						*dst++ = (uint8_t)clamp((density_cpu[x + z*res3d.x + y*res3d.x*res3d.z]-thresh)*density_scale + 128.5f, 0.f, 255.f);
1015					} else {
1016						*dst++ = (uint8_t)clamp((density_cpu[x + (res3d.y-1-y)*res3d.x + z*res3d.x*res3d.y]-thresh)*density_scale + 128.5f, 0.f, 255.f);
1017					}
1018				} else {
1019					*dst++ = 0;
1020				}
1021			}
1022		}
1023	
1024		write_stbi(path, w, h, 1, pngpixels);
1025	
1026		tlog::success() << "Wrote density PNG to " << path.str();
1027		tlog::info()
1028			<< "  #lattice points=" << N
1029			<< " #zero-x voxels=" << num_voxels << " (" << ((num_voxels*100.0)/N) << "%%)"
1030			<< " #lattice near zero-x=" << num_lattice_points_near_zero_crossing << " (" << ((num_lattice_points_near_zero_crossing*100.0)/N) << "%%)";
1031	
1032		free(pngpixels);
1033	}
1034	
1035	// Distinct from `save_density_grid_to_png` not just in that is writes RGBA, but also
1036	// in that it writes a sequence of PNGs rather than a single large PNG.
1037	// TODO: make both methods configurable to do either single PNG or PNG sequence.
1038	void save_rgba_grid_to_png_sequence(const GPUMemory<vec4>& rgba, const fs::path& path, ivec3 res3d, bool swap_y_z) {
1039		std::vector<vec4> rgba_cpu;
1040		rgba_cpu.resize(rgba.size());
1041		rgba.copy_to_host(rgba_cpu);
1042	
1043		if (swap_y_z) {
1044			res3d = {res3d.x, res3d.z, res3d.y};
1045		}
1046	
1047		uint32_t w = res3d.x;
1048		uint32_t h = res3d.y;
1049	
1050		auto progress = tlog::progress(res3d.z);
1051	
1052		std::atomic<int> n_saved{0};
1053		ThreadPool{}.parallel_for<int>(0, res3d.z, [&](int z) {
1054			uint8_t* pngpixels = (uint8_t*)malloc(size_t(w) * size_t(h) * 4);
1055			uint8_t* dst = pngpixels;
1056			for (int y = 0; y < h; ++y) {
1057				for (int x = 0; x < w; ++x) {
1058					size_t i = swap_y_z ? (x + z*res3d.x + y*res3d.x*res3d.z) : (x + (res3d.y-1-y)*res3d.x + z*res3d.x*res3d.y);
1059					*dst++ = (uint8_t)clamp(rgba_cpu[i].x * 255.f, 0.f, 255.f);
1060					*dst++ = (uint8_t)clamp(rgba_cpu[i].y * 255.f, 0.f, 255.f);
1061					*dst++ = (uint8_t)clamp(rgba_cpu[i].z * 255.f, 0.f, 255.f);
1062					*dst++ = (uint8_t)clamp(rgba_cpu[i].w * 255.f, 0.f, 255.f);
1063				}
1064			}
1065	
1066			write_stbi(path / fmt::format("{:04d}_{}x{}.png", z, w, h), w, h, 4, pngpixels);
1067			free(pngpixels);
1068	
1069			progress.update(++n_saved);
1070		});
1071		tlog::success() << "Wrote RGBA PNG sequence to " << path;
1072	}
1073	
1074	void save_rgba_grid_to_raw_file(const GPUMemory<vec4>& rgba, const fs::path& path, ivec3 res3d, bool swap_y_z, int cascade) {
1075		std::vector<vec4> rgba_cpu;
1076		rgba_cpu.resize(rgba.size());
1077		rgba.copy_to_host(rgba_cpu);
1078	
1079		if (swap_y_z) {
1080			res3d = {res3d.x, res3d.z, res3d.y};
1081		}
1082	
1083		uint32_t w = res3d.x;
1084		uint32_t h = res3d.y;
1085		uint32_t d = res3d.z;
1086	
1087		auto actual_path = path / fmt::format("{}x{}x{}_{}.bin", w, h, d, cascade);
1088		FILE* f = native_fopen(actual_path, "wb");
1089		if (!f)
1090			return ;
1091		const static float zero[4]={0.f,0.f,0.f,0.f};
1092		int border = 1; // extra ring of voxels to make the donut hole smaller
1093		for (int z = 0; z < d; ++z) {
1094			for (int y = 0; y < h; ++y) {
1095				for (int x = 0; x < w; ++x) {
1096					size_t i = swap_y_z ? (x + z*res3d.x + y*res3d.x*res3d.z) : (x + (res3d.y-1-y)*res3d.x + z*res3d.x*res3d.y);
1097					float* rgba = (float*)&rgba_cpu[i];
1098					// the intention is that if cascade > 0, we have set up the render aabb such that we are outputing exactly one cascade of the nerf
1099					// we then punch a transparent hole in the middle of each cascade, so that they fit together when placed on top of each other.
1100					if (cascade && x>=res3d.x/4+border && y>=res3d.y/4+border && z>=res3d.z/4+border && x<res3d.x-res3d.x/4-border && y<res3d.y-res3d.y/4-border && z<res3d.z-res3d.z/4-border)
1101						fwrite(zero, sizeof(float), 4, f);
1102					else
1103						fwrite(rgba, sizeof(float), 4, f);
1104				}
1105			}
1106		}
1107		fclose(f);
1108		tlog::success() << "Wrote RGBA raw file to " << actual_path.str();
1109	}
1110	
1111	}
