	uint32_t res1=res_3d.x;
	uint32_t res2=res_3d.x*res_3d.y;
	uint32_t res3=res_3d.x*res_3d.y*res_3d.z;
	uint32_t idx=x+y*res_3d.x+z*res2;

	uint32_t idx_x=idx;
	uint32_t idx_y=idx+res3;
	uint32_t idx_z=idx+res3*2;

